import{_ as e,o as l,c as n,a2 as a}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"6290 良維 — 供應鏈拆解","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/供應鏈拆解/6290_良維_供應鏈.md","filePath":"Deep32Q知識庫/供應鏈拆解/6290_良維_供應鏈.md"}'),d={name:"Deep32Q知識庫/供應鏈拆解/6290_良維_供應鏈.md"};function r(s,t,i,g,o,x){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="_6290-良維-—-供應鏈拆解" tabindex="-1">6290 良維 — 供應鏈拆解 <a class="header-anchor" href="#_6290-良維-—-供應鏈拆解" aria-label="Permalink to &quot;6290 良維 — 供應鏈拆解&quot;">​</a></h1><blockquote><p>最後更新：2026-04-26 | 知識來源：良維各股摘要（F01-F13）</p></blockquote><hr><h2 id="一、公司定位與供應鏈角色" tabindex="-1">一、公司定位與供應鏈角色 <a class="header-anchor" href="#一、公司定位與供應鏈角色" aria-label="Permalink to &quot;一、公司定位與供應鏈角色&quot;">​</a></h2><p>良維（6290）為台灣電源線組與連接器製造商，成立逾 50 年。2023-2025 年間完成<strong>結構性產品組合轉型</strong>，從消費電子電源線/連接器（Apple 供應鏈為主）轉向高毛利數據中心/AI 伺服器電源解決方案。</p><p><strong>供應鏈定位：中游製造商（OEM/ODM）</strong></p><ul><li>上游：銅材、塑膠樹脂、金屬接頭、包裝材料</li><li>中游：良維（設計、安規認證、製造、組裝）</li><li>下游：CSP 雲端服務商、消費電子品牌、電動車廠</li></ul><hr><h2 id="二、上游供應商分析" tabindex="-1">二、上游供應商分析 <a class="header-anchor" href="#二、上游供應商分析" aria-label="Permalink to &quot;二、上游供應商分析&quot;">​</a></h2><h3 id="_2-1-關鍵原材料" tabindex="-1">2.1 關鍵原材料 <a class="header-anchor" href="#_2-1-關鍵原材料" aria-label="Permalink to &quot;2.1 關鍵原材料&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">原料</th><th style="text-align:center;">成本佔比推估</th><th style="text-align:left;">供應特性</th><th style="text-align:left;">議價能力</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>銅材</strong></td><td style="text-align:center;">30-40%（COGS 主項）</td><td style="text-align:left;">國際大宗商品，LME 銅價波動</td><td style="text-align:left;">⚠️ 中低 — 有轉嫁機制但存在時間差</td></tr><tr><td style="text-align:left;"><strong>塑膠樹脂（PBT/PA66）</strong></td><td style="text-align:center;">10-15%</td><td style="text-align:left;">石化下游，台塑/奇美等供應</td><td style="text-align:left;">⚠️ 中 — 多源採購分散風險</td></tr><tr><td style="text-align:left;"><strong>金屬接頭（鍍金/鍍錫）</strong></td><td style="text-align:center;">15-20%</td><td style="text-align:left;">特殊規格需客製，認證週期長</td><td style="text-align:left;">✅ 中高 — 安規認證門檻形成壁壘</td></tr><tr><td style="text-align:left;"><strong>矽膠/密封材料</strong></td><td style="text-align:center;">5-8%</td><td style="text-align:left;">標準品，多供應商可選</td><td style="text-align:left;">✅ 高 — 替代性強</td></tr><tr><td style="text-align:left;"><strong>包裝材料</strong></td><td style="text-align:center;">3-5%</td><td style="text-align:left;">低技術門檻，在地採購</td><td style="text-align:left;">✅ 高 — 完全競爭市場</td></tr></tbody></table><h3 id="_2-2-設備與零組件供應商" tabindex="-1">2.2 設備與零組件供應商 <a class="header-anchor" href="#_2-2-設備與零組件供應商" aria-label="Permalink to &quot;2.2 設備與零組件供應商&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>自動化組裝設備</strong></td><td style="text-align:left;">自製/客製化，部分來自台灣設備商（如大立、東信）</td></tr><tr><td style="text-align:left;"><strong>測試儀器</strong></td><td style="text-align:left;">安規測試設備（UL/CE/TÜV 認證用），部分進口</td></tr><tr><td style="text-align:left;"><strong>模具</strong></td><td style="text-align:left;">內部設計+外部加工，關鍵競爭力之一</td></tr></tbody></table><h3 id="_2-3-上游議價能力評估" tabindex="-1">2.3 上游議價能力評估 <a class="header-anchor" href="#_2-3-上游議價能力評估" aria-label="Permalink to &quot;2.3 上游議價能力評估&quot;">​</a></h3><p><strong>良維對上游的議價力：中等偏上（B+）</strong></p><p>論據：</p><ul><li>銅材佔 COGS 比重高，但良維已建立<strong>價格轉嫁機制</strong>（與客戶合約中納入銅價調整條款）</li><li>塑膠樹脂、金屬接頭多源採購，分散單一供應商風險</li><li>規模效應：營收從 73 億→102 億，採購量提升增強議價力</li><li>關鍵金屬接頭的安規認證（UL/CE）形成壁壘，替換成本高</li></ul><p><strong>風險點：</strong></p><ul><li>銅價劇烈波動時存在轉嫁時間差（約 1-3 個月），短期侵蝕毛利率</li><li>地緣政治影響銅、塑膠原料供應鏈穩定性</li></ul><hr><h2 id="三、下游客戶分析" tabindex="-1">三、下游客戶分析 <a class="header-anchor" href="#三、下游客戶分析" aria-label="Permalink to &quot;三、下游客戶分析&quot;">​</a></h2><h3 id="_3-1-客戶結構-2026-年預估權重" tabindex="-1">3.1 客戶結構（2026 年預估權重） <a class="header-anchor" href="#_3-1-客戶結構-2026-年預估權重" aria-label="Permalink to &quot;3.1 客戶結構（2026 年預估權重）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">客戶類別</th><th style="text-align:center;">營收佔比</th><th style="text-align:left;">代表客戶</th><th style="text-align:left;">特性</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>數據中心/AI 伺服器</strong></td><td style="text-align:center;">~50%</td><td style="text-align:left;">Amazon、Google、Meta（CSP）</td><td style="text-align:left;">高毛利、長訂單能見度、技術門檻高</td></tr><tr><td style="text-align:left;"><strong>消費電子（Apple 供應鏈）</strong></td><td style="text-align:center;">~25%</td><td style="text-align:left;">Apple、相關 ODM（鴻海、富士康）</td><td style="text-align:left;">品質認證門檻極高，訂單穩定但毛利較低</td></tr><tr><td style="text-align:left;"><strong>電動車充電連接器</strong></td><td style="text-align:center;">~15%</td><td style="text-align:left;">電動車廠/充電站營運商</td><td style="text-align:left;">長期布局，成長快速但佔比仍低</td></tr><tr><td style="text-align:left;"><strong>其他（家電、工業）</strong></td><td style="text-align:center;">~10%</td><td style="text-align:left;">多品牌 OEM/ODM 客戶</td><td style="text-align:left;">分散風險，毛利一般</td></tr></tbody></table><h3 id="_3-2-下游客戶議價能力評估" tabindex="-1">3.2 下游客戶議價能力評估 <a class="header-anchor" href="#_3-2-下游客戶議價能力評估" aria-label="Permalink to &quot;3.2 下游客戶議價能力評估&quot;">​</a></h3><p><strong>客戶對良維的議價力：中等（B）</strong> — 結構性改善中</p><p>論據：</p><ul><li><strong>客戶集中度風險</strong>：Apple + Amazon 佔比偏高，單一客戶訂單波動影響大</li><li><strong>數據中心客戶議價力較低</strong>：CSP 客戶（Amazon/Google/Meta）因良維的安規認證壁壘、12-18 個月認證週期、客製化設計能力，替換成本高</li><li><strong>Apple 供應鏈議價力較高</strong>：消費電子電源線同業競爭激烈，但良維已透過高附加價值產品降低依賴</li><li><strong>認證壁壘</strong>：33 國安規認證存量、50 年累積，新進者難以短期複製</li></ul><h3 id="_3-3-客戶黏著度" tabindex="-1">3.3 客戶黏著度 <a class="header-anchor" href="#_3-3-客戶黏著度" aria-label="Permalink to &quot;3.3 客戶黏著度&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">維度</th><th style="text-align:left;">評估</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>認證週期</strong></td><td style="text-align:left;">12-18 個月（新客戶），替換成本極高</td></tr><tr><td style="text-align:left;"><strong>客製化程度</strong></td><td style="text-align:left;">高 — 各客戶規格差異大，標準品佔比低</td></tr><tr><td style="text-align:left;"><strong>訂單能見度</strong></td><td style="text-align:left;">3-6 個月（正式），實際可透過月營收趨勢推估至 12 個月</td></tr><tr><td style="text-align:left;"><strong>轉換成本</strong></td><td style="text-align:left;">極高 — 需重新通過安規認證、測試驗證、量產磨合</td></tr></tbody></table><hr><h2 id="四、關鍵零組件與產品組合" tabindex="-1">四、關鍵零組件與產品組合 <a class="header-anchor" href="#四、關鍵零組件與產品組合" aria-label="Permalink to &quot;四、關鍵零組件與產品組合&quot;">​</a></h2><h3 id="_4-1-核心產品線" tabindex="-1">4.1 核心產品線 <a class="header-anchor" href="#_4-1-核心產品線" aria-label="Permalink to &quot;4.1 核心產品線&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">產品類別</th><th style="text-align:center;">營收佔比（2025）</th><th style="text-align:center;">毛利率區間</th><th style="text-align:left;">關鍵特徵</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>數據中心/AI 伺服器電源連接器</strong></td><td style="text-align:center;">~36%（佔總營收）</td><td style="text-align:center;"><strong>35-40%</strong></td><td style="text-align:left;">大電流 30A→100A+，HVDC 800V（NVIDIA Vera Rubin 平台）</td></tr><tr><td style="text-align:left;"><strong>Apple 供應鏈電源線組</strong></td><td style="text-align:center;">~25%</td><td style="text-align:center;">20-25%</td><td style="text-align:left;">品質認證門檻高，訂單穩定</td></tr><tr><td style="text-align:left;"><strong>電動車充電連接器</strong></td><td style="text-align:center;">~15%</td><td style="text-align:center;">25-30%</td><td style="text-align:left;">長期布局，認證通過中</td></tr><tr><td style="text-align:left;"><strong>其他消費電子/工業</strong></td><td style="text-align:center;">~24%</td><td style="text-align:center;">18-22%</td><td style="text-align:left;">家電、工業設備電源線</td></tr></tbody></table><h3 id="_4-2-關鍵技術壁壘" tabindex="-1">4.2 關鍵技術壁壘 <a class="header-anchor" href="#_4-2-關鍵技術壁壘" aria-label="Permalink to &quot;4.2 關鍵技術壁壘&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">壁壘類型</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>33 國安規認證</strong></td><td style="text-align:left;">UL、CE、TÜV 等，新進者需逐一取得，耗時長</td></tr><tr><td style="text-align:left;"><strong>大電流技術</strong></td><td style="text-align:left;">從 30A 擴充至 100A+，滿足 AI 伺服器 700W→1500W+ 功耗</td></tr><tr><td style="text-align:left;"><strong>HVDC（高壓直流）</strong></td><td style="text-align:left;">800V 配合 NVIDIA Vera Rubin 平台，先發優勢</td></tr><tr><td style="text-align:left;"><strong>客製化設計能力</strong></td><td style="text-align:left;">單價較高，客戶認證週期 12-24 個月</td></tr><tr><td style="text-align:left;"><strong>品質管理體系</strong></td><td style="text-align:left;">Apple 供應鏈認證，同業難以短期複製</td></tr></tbody></table><h3 id="_4-3-關鍵零組件成本結構-cogs-分解推估" tabindex="-1">4.3 關鍵零組件成本結構（COGS 分解推估） <a class="header-anchor" href="#_4-3-關鍵零組件成本結構-cogs-分解推估" aria-label="Permalink to &quot;4.3 關鍵零組件成本結構（COGS 分解推估）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:center;">COGS 佔比</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>銅材</strong></td><td style="text-align:center;">30-40%</td><td style="text-align:left;">最大成本項目，隨 LME 銅價波動</td></tr><tr><td style="text-align:left;"><strong>塑膠樹脂</strong></td><td style="text-align:center;">10-15%</td><td style="text-align:left;">PBT/PA66 等工程塑膠</td></tr><tr><td style="text-align:left;"><strong>金屬接頭</strong></td><td style="text-align:center;">15-20%</td><td style="text-align:left;">鍍金/鍍錫接頭，客製化規格</td></tr><tr><td style="text-align:left;"><strong>矽膠/密封材料</strong></td><td style="text-align:center;">5-8%</td><td style="text-align:left;">防水、密封用</td></tr><tr><td style="text-align:left;"><strong>直接人工</strong></td><td style="text-align:center;">10-12%</td><td style="text-align:left;">中國+東南亞產能，成本優勢</td></tr><tr><td style="text-align:left;"><strong>製造費用（折舊/水電）</strong></td><td style="text-align:center;">5-8%</td><td style="text-align:left;">泰國廠擴產後折舊增加，但已近尾聲</td></tr><tr><td style="text-align:left;"><strong>其他（包裝/物流）</strong></td><td style="text-align:center;">3-5%</td><td style="text-align:left;">—</td></tr></tbody></table><blockquote><p>⚠️ COGS 總計約佔營收 68.6%（FY2025），毛利率 31.4%</p></blockquote><hr><h2 id="五、成本結構深度分析" tabindex="-1">五、成本結構深度分析 <a class="header-anchor" href="#五、成本結構深度分析" aria-label="Permalink to &quot;五、成本結構深度分析&quot;">​</a></h2><h3 id="_5-1-總體成本結構-fy2025" tabindex="-1">5.1 總體成本結構（FY2025） <a class="header-anchor" href="#_5-1-總體成本結構-fy2025" aria-label="Permalink to &quot;5.1 總體成本結構（FY2025）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">成本類別</th><th style="text-align:center;">佔營收比</th><th style="text-align:left;">性質</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>COGS（銷貨成本）</strong></td><td style="text-align:center;">68.6%</td><td style="text-align:left;">變動為主</td><td style="text-align:left;">銅材、塑膠、人工、製造費用</td></tr><tr><td style="text-align:left;"><strong>營業費用</strong></td><td style="text-align:center;">14.0%</td><td style="text-align:left;">固定為主</td><td style="text-align:left;">R&amp;D（0.8%）+ 管銷（13.2%）</td></tr><tr><td style="text-align:left;"><strong>固定成本合計</strong></td><td style="text-align:center;">~13-15%</td><td style="text-align:left;">固定</td><td style="text-align:left;">D&amp;A（2.2%）+ 核心薪資 + 固定管銷</td></tr><tr><td style="text-align:left;"><strong>變動成本合計</strong></td><td style="text-align:center;">~71-73%</td><td style="text-align:left;">變動</td><td style="text-align:left;">COGS + 變動管銷</td></tr><tr><td style="text-align:left;"><strong>邊際貢獻率</strong></td><td style="text-align:center;">~24.4%</td><td style="text-align:left;">—</td><td style="text-align:left;">營收 − 變動成本</td></tr></tbody></table><h3 id="_5-2-經營槓桿分析" tabindex="-1">5.2 經營槓桿分析 <a class="header-anchor" href="#_5-2-經營槓桿分析" aria-label="Permalink to &quot;5.2 經營槓桿分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">數值</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>DOL（經營槓桿倍數）</strong></td><td style="text-align:center;">5.81x</td><td style="text-align:left;">營收 +34.7% → 營業利益 +201.8%</td></tr><tr><td style="text-align:left;"><strong>損益平衡營收</strong></td><td style="text-align:center;">~38.3 億元</td><td style="text-align:left;">FY2025 營收的 38%，安全邊際 62%</td></tr><tr><td style="text-align:left;"><strong>產能利用率</strong></td><td style="text-align:center;">70-80%（泰國廠）</td><td style="text-align:left;">接近甜蜜點，再提升將啟動獲利加速</td></tr><tr><td style="text-align:left;"><strong>規模經濟臨界點</strong></td><td style="text-align:center;">60-80 億元</td><td style="text-align:left;">跨越後每增 20 億營收挹注 ~4.9 億營利</td></tr></tbody></table><h3 id="_5-3-成本結構優劣勢" tabindex="-1">5.3 成本結構優劣勢 <a class="header-anchor" href="#_5-3-成本結構優劣勢" aria-label="Permalink to &quot;5.3 成本結構優劣勢&quot;">​</a></h3><p><strong>優勢：</strong></p><ul><li>✅ 損益平衡點極低（38.3 億），安全邊際充裕</li><li>✅ 變動成本主導（COGS 68.6%），景氣下行時自動縮減提供緩衝</li><li>✅ 固定成本可控（12-15%），D&amp;A/營收僅 2.2%</li><li>✅ 泰國廠擴產完成後折舊壓力減小，進入收割期</li></ul><p><strong>劣勢/風險：</strong></p><ul><li>⚠️ 銅材佔比高，價格波動直接影響毛利率</li><li>⚠️ 景氣下行時獲利敏感度約 1.6x（營收 -30% → 獲利 -48%）</li><li>⚠️ Q4 行銷費用率異常偏高（18.83%），需持續監控</li></ul><hr><h2 id="六、議價能力綜合評估" tabindex="-1">六、議價能力綜合評估 <a class="header-anchor" href="#六、議價能力綜合評估" aria-label="Permalink to &quot;六、議價能力綜合評估&quot;">​</a></h2><h3 id="_6-1-上下游議價力矩陣" tabindex="-1">6.1 上下游議價力矩陣 <a class="header-anchor" href="#_6-1-上下游議價力矩陣" aria-label="Permalink to &quot;6.1 上下游議價力矩陣&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">維度</th><th style="text-align:left;">良維地位</th><th style="text-align:center;">評分</th><th style="text-align:left;">關鍵論據</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>對上游供應商</strong></td><td style="text-align:left;">中等偏上</td><td style="text-align:center;">B+</td><td style="text-align:left;">銅價轉嫁機制、多源採購、規模效應</td></tr><tr><td style="text-align:left;"><strong>對下游客戶</strong></td><td style="text-align:left;">中等（改善中）</td><td style="text-align:center;">B</td><td style="text-align:left;">客戶集中度風險 vs 認證壁壘、客製化能力</td></tr><tr><td style="text-align:left;"><strong>整體議價權</strong></td><td style="text-align:left;">結構性增強</td><td style="text-align:center;">A-</td><td style="text-align:left;">毛利率從 22.8%→34.8%，定價權顯著提升</td></tr></tbody></table><h3 id="_6-2-議價能力驅動因子" tabindex="-1">6.2 議價能力驅動因子 <a class="header-anchor" href="#_6-2-議價能力驅動因子" aria-label="Permalink to &quot;6.2 議價能力驅動因子&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">因子</th><th style="text-align:center;">方向</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>產品組合優化</strong></td><td style="text-align:center;">正向↑</td><td style="text-align:left;">數據中心高毛利產品佔比從 &lt;10%→36%</td></tr><tr><td style="text-align:left;"><strong>安規認證壁壘</strong></td><td style="text-align:center;">正向↑</td><td style="text-align:left;">33 國認證、50 年累積，新進者難以複製</td></tr><tr><td style="text-align:left;"><strong>客戶集中度</strong></td><td style="text-align:center;">負向↓</td><td style="text-align:left;">Apple/Amazon 佔比偏高，單一客戶波動影響大</td></tr><tr><td style="text-align:left;"><strong>銅價轉嫁機制</strong></td><td style="text-align:center;">中性→</td><td style="text-align:left;">有合約調整條款，但存在 1-3 個月時間差</td></tr><tr><td style="text-align:left;"><strong>規模經濟</strong></td><td style="text-align:center;">正向↑</td><td style="text-align:left;">營收 73→102 億，採購量提升增強議價力</td></tr><tr><td style="text-align:left;"><strong>替代威脅</strong></td><td style="text-align:center;">負向↓</td><td style="text-align:left;">消費電子電源線同業競爭仍激烈</td></tr></tbody></table><h3 id="_6-3-定價權實證" tabindex="-1">6.3 定價權實證 <a class="header-anchor" href="#_6-3-定價權實證" aria-label="Permalink to &quot;6.3 定價權實證&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">2023</th><th style="text-align:center;">2024</th><th style="text-align:center;">2025</th><th style="text-align:center;">趨勢</th></tr></thead><tbody><tr><td style="text-align:left;">毛利率</td><td style="text-align:center;">22.8%</td><td style="text-align:center;">25.1%</td><td style="text-align:center;"><strong>31.4%</strong></td><td style="text-align:center;">↑↑↑</td></tr><tr><td style="text-align:left;">Q4 毛利率（最高）</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;"><strong>34.8%</strong></td><td style="text-align:center;">歷史新高</td></tr><tr><td style="text-align:left;">營業利益率</td><td style="text-align:center;">7.6%</td><td style="text-align:center;">12.4%</td><td style="text-align:center;"><strong>17.9%</strong></td><td style="text-align:center;">↑↑↑</td></tr><tr><td style="text-align:left;">DOL（經營槓桿）</td><td style="text-align:center;">—</td><td style="text-align:center;">3.41x</td><td style="text-align:center;"><strong>5.81x</strong></td><td style="text-align:center;">高彈性</td></tr></tbody></table><blockquote><p>定價權增強的三大驅動：產品組合優化 + 銅價成功轉嫁 + 規模經濟（固定成本攤提）</p></blockquote><hr><h2 id="七、供應鏈地理分佈" tabindex="-1">七、供應鏈地理分佈 <a class="header-anchor" href="#七、供應鏈地理分佈" aria-label="Permalink to &quot;七、供應鏈地理分佈&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">生產基地</th><th style="text-align:left;">主要產品</th><th style="text-align:left;">產能角色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中國</strong></td><td style="text-align:left;">消費電子電源線、部分連接器</td><td style="text-align:left;">傳統產能，逐年縮編低毛利業務</td></tr><tr><td style="text-align:left;"><strong>泰國（一廠+二廠已完工）</strong></td><td style="text-align:left;">數據中心/AI 伺服器連接器</td><td style="text-align:left;">主力產能，產能利用率 70-80%</td></tr><tr><td style="text-align:left;"><strong>泰國（三廠擴建中）</strong></td><td style="text-align:left;">數據中心/AI 伺服器連接器</td><td style="text-align:left;">預計再增 10%+ 產能</td></tr><tr><td style="text-align:left;"><strong>馬來西亞</strong></td><td style="text-align:left;">連接器組裝</td><td style="text-align:left;">分散風險，配合客戶需求</td></tr><tr><td style="text-align:left;"><strong>印度（布局中）</strong></td><td style="text-align:left;">當地市場產品</td><td style="text-align:left;">長期戰略佈局</td></tr></tbody></table><blockquote><p>生產基地分散策略降低地緣政治風險，符合 Apple/CSP 客戶的供應鏈多元化要求。</p></blockquote><hr><h2 id="八、供應鏈風險總覽" tabindex="-1">八、供應鏈風險總覽 <a class="header-anchor" href="#八、供應鏈風險總覽" aria-label="Permalink to &quot;八、供應鏈風險總覽&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">風險因子</th><th style="text-align:center;">影響程度</th><th style="text-align:left;">緩解措施</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>客戶集中度</strong></td><td style="text-align:center;">中高</td><td style="text-align:left;">數據中心客戶佔比提升至 50%，分散 Apple 依賴</td></tr><tr><td style="text-align:left;"><strong>銅價波動</strong></td><td style="text-align:center;">中</td><td style="text-align:left;">合約價格轉嫁機制，但存在時間差</td></tr><tr><td style="text-align:left;"><strong>AI Capex 週期</strong></td><td style="text-align:center;">中</td><td style="text-align:left;">產品組合多元化（消費電子 25%、車用 15%）</td></tr><tr><td style="text-align:left;"><strong>地緣政治</strong></td><td style="text-align:center;">中</td><td style="text-align:left;">生產基地分散（中國、泰國、馬來西亞、印度）</td></tr><tr><td style="text-align:left;"><strong>匯率風險</strong></td><td style="text-align:center;">中</td><td style="text-align:left;">營收以美元計價，台幣升值影響毛利率（FY2025 已出現 -7,717 萬匯兌損失）</td></tr><tr><td style="text-align:left;"><strong>技術路線風險</strong></td><td style="text-align:center;">低中</td><td style="text-align:left;">無線電力傳輸若普及將衝擊實體電源線需求，但短期（2025-2030）可控</td></tr></tbody></table><hr><h2 id="九、供應鏈總結" tabindex="-1">九、供應鏈總結 <a class="header-anchor" href="#九、供應鏈總結" aria-label="Permalink to &quot;九、供應鏈總結&quot;">​</a></h2><p><strong>良維供應鏈核心特徵：</strong></p><ol><li><strong>中游製造商定位清晰</strong>：上游原材料（銅、塑膠）→ 中游設計/認證/製造 → 下游 CSP/消費電子品牌</li><li><strong>結構性轉型成功</strong>：從低毛利消費電子轉向高毛利數據中心，毛利率 22.8%→34.8%</li><li><strong>議價能力結構性增強</strong>：安規認證壁壘、客製化設計、客戶黏著度（12-18 個月認證週期）</li><li><strong>地理分散策略</strong>：中國、泰國、馬來西亞、印度多基地佈局，符合國際客戶供應鏈多元化需求</li><li><strong>關鍵競爭優勢</strong>：33 國安規認證、大電流技術（100A+）、HVDC 先發優勢、Apple 供應鏈品質認證</li></ol><hr><p><em>本文件基於良維知識庫（F01-F13）整理，資料期間 2023-2025，來源 FinMind API + 公開資訊觀測站。</em><em>知識庫更新：2026-04-26 新增供應鏈拆解文件</em></p>',71)])])}const f=e(d,[["render",r]]);export{h as __pageData,f as default};
